var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"오늘은 길을 걷다 빗물에 미끄러져서 전봇대에 코를 부딪혔다고?","JPN":"今日は道を歩いていて、雨水に滑って電柱に鼻をぶつけたと？","ENG":"So you smashed your nose against a utility pole after slipping in the rain while walking?","TWN":"你今天是走在路上，因為雨水滑倒，結果撞上電線桿、撞到鼻子了？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그렇도다.","JPN":"そうだ。","ENG":"Correct.","TWN":"就是這樣。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"다음엔 넘어지면서 보드에 올라타면서, 그대로 내리막길을 질주했다는 거지?","JPN":"それで姿勢を崩したままボードに乗っちゃって、そのまま下り道を疾走したと。","ENG":"Then you fell onto a board and raced downhill on it?","TWN":"然後是跌倒時順勢踩上滑板，一路往下坡衝？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"흔히 있는 일이니라.","JPN":"よくあることなのだ。","ENG":"It is a common occurrence.","TWN":"這是常有的事。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"가속도가 붙은 채로 소화전에 충돌… 그대로 날아올라 전깃줄에 걸려 감전… 달리는 버스 위로 떨어져 놀란 기사가 급정지함과 동시에 정면으로 날아가서…","JPN":"加速度がついたまま消火栓に衝突……そのまま飛び上がって電線に引っかかって感電……走るバスの上に落ちて驚いた運転手が急停止することと同時に正面に飛ばされて……","ENG":"Crashing into a fire hydrant while accelerating... Then flying straight into the air, getting electrocuted after getting caught in the electric wire... Falling on top of a moving bus, causing the startled bus driver to suddenly stop, and flying straight ahead...","TWN":"你在加速狀態下撞上消防栓……整個人飛起來掛在電線上觸電……又掉到行進中的公車車頂，嚇得司機緊急煞車，你又直接飛出去……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"으흠… 아무튼 이 뒤로 연달아 6번의 사고가 더 일어났구나.","JPN":"ふーん……とにかく、それから6回の事故が相次いだんだな。","ENG":"Hmm... Anyway, it looks like you got into six more accidents after that.","TWN":"嗯……總之在這之後，又接連發生了6起事故。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"더 말해 뭐하겠느냐.","JPN":"言わずともわかるであろう。","ENG":"What more is there for me to say?","TWN":"我無言以對。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"선생님! 모모가 얼마나 다친 건가요?!","JPN":"先生！　モモって、どれほど怪我したんですか！？","ENG":"Doctor! Is Momo okay?!","TWN":"醫生！莫莫到底傷得多重？！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"여기에 쓰여진 대로라면 전치 6개월은 거뜬하겠네요.","JPN":"ここに書かれている通りだと、全治6か月はなるでしょうね。","ENG":"Reading what's written here, it should take about six months to fully heal.","TWN":"照這裡的記錄來看，至少需要休養6個月。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"전치 6개월? 그 정도로 많이 다친 건가요?!","JPN":"全治6か月？　そんなに大怪我なんですか！？","ENG":"Six months? Is she hurt that severely?!","TWN":"6個月？！她傷得這麼重嗎？！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"좀 더 직설적으로 표현하자면… 살아있는 게 기적이라고 봐야할 정도입니다.","JPN":"もっとズバリ言うと……生きているのが奇跡なんです。","ENG":"To put it more bluntly... It's a miracle she's still alive.","TWN":"我說得更直接一點……她還活著本身就是奇蹟了。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저… 실은 오는 길에 모모가 때를 써서 사탕을 하나 사줬는데요.","JPN":"あの……実はここに来る途中にモモが我がまま言うからキャンディを1つ買ってあげたんです。","ENG":"I... bought Momo a piece of candy on the way.","TWN":"那個……其實在來的路上，莫莫吵著要吃糖，我就買了一顆給她……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"혹시 당분이 부상에 악영향을 줄까요?!","JPN":"もしかして、糖分が怪我に悪影響を与えることってありますか！？","ENG":"Could the sugar have negative effects on her injuries?!","TWN":"糖分會不會對傷勢有不良的影響？！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"그, 그렇게까지 걱정하지 않으셔도 됩니다. 검진 결과, 몸에 특별한 이상은 없었으니까요.","JPN":"そ、そこまで心配する必要はないですよ。検診の結果、体に別状はなかったんですから。","ENG":"Y-you don't have to worry that much. According to the examinations, there's nothing wrong with her.","TWN":"不、不用那麼擔心。根據檢查結果，她的身體並沒有異常。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"당연하지 않느냐? 이 몸은 마왕이다.","JPN":"当然だ。吾輩は魔王なのだぞ。","ENG":"Of course, there's not! I am a Demon Lord!","TWN":"那是當然的吧？我可是魔王。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"휴우, 다행이네요. 이번에도 운이 좋았나 봐요.","JPN":"ふう、よかったですね。今度も運がよかったみたいです。","ENG":"Phew, that's good to hear. Guess she got lucky again.","TWN":"呼，那真是太好了。看來這次也算運氣不錯。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"글쎄요. 운이 좋았다고 하기엔 이번 달만 벌써 병원을 아홉 번째 찾아오셨습니다.","JPN":"どうでしょう。運がよかったことにしては、今月に入ってもう9番目の訪問ですよ。","ENG":"I don't think it's luck. This is her ninth visit to the hospital this month.","TWN":"是啊。雖然這麼說，但光是這個月，你們已經來醫院第九次了。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"제가 미신은 믿지 않는 편입니다만, 두 분에겐 무당집이라도 알아보는 걸 진지하게 권해드리고 싶네요.","JPN":"私は迷信を信じない方なんですが、お二人には祓い屋でも探してみた方がいいんじゃないでしょうかね。","ENG":"I don't believe in superstitions, but I strongly advise you to take her to see a shaman.","TWN":"雖然我不太迷信，但真心建議你們要不要找個巫師？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"음? 의료보험이라고?","JPN":"うん？　医療保険？","ENG":"Hmm? Medical insurance?","TWN":"嗯？醫療保險？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네, 의사선생님이 만일을 대비하는 게 좋다면서 몇 군데 소개해주셨어요.","JPN":"はい、医者さんが万が一に備えた方がいいっていくつか紹介してくれたんです。","ENG":"Yes, the doctor recommended a few just to be safe.","TWN":"對。醫生說為了以防萬一，介紹了幾種方案。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"흐음… 요즘에는 별의별 보험이 다 있네. 다이브 실종 특약 같은 것도 있구나.","JPN":"ふーん……最近は色んな保険があるわね。ダイブ失踪特約とかもあるじゃない。","ENG":"Hmm... There are all kinds of insurance these days. There are even ones with special conditions for going missing on dives.","TWN":"唔……現在的保險還真是五花八門，還有潛水失蹤的附加條款。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그레모리 씨는 오늘 외출이라도 나가시나 봐요?","JPN":"グレモリーさんは、今日お出かけなんですか？","ENG":"Gremory, are you going out today?","TWN":"葛茉莉小姐今天要出門啊？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어머, 눈치챘어?","JPN":"あら、気付いた？","ENG":"Oh, did you notice?","TWN":"哎呀，被你發現啦？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그야 평소보다 덜 취해계신 것 같아서요.","JPN":"いつもより酔ってないなーと思って。","ENG":"Well, you seem less drunk than usual.","TWN":"因為你看起來比平常清醒一點。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"후훗, 니콜 양은 은근히 예리해서 거짓말도 못하겠다니까.","JPN":"ふふっ、ニコルちゃんは鋭くて嘘もつけないわね。","ENG":"Hah hah, you're so keen that I can't lie to you, Nicole.","TWN":"呵呵，妮可小姐其實挺敏銳的，害我都不能說謊呢。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"간만에 만화방이나 좀 다녀오려고 해. 꼬마 주인님이랑.","JPN":"久しぶりにマンガ喫茶に行ってこようと思ったの。王様とね。","ENG":"I'm thinking of going to the comic book store with our little majesty.","TWN":"我好久沒去漫畫店了，想跟小主人一起去一趟。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"모모와 만화방이요?","JPN":"モモとマンガ喫茶ですか？","ENG":"The comic book store with Momo?","TWN":"你要和莫莫去漫畫店嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"갖고 싶은 책이 있으면 말해. 내가 사줄 테니까.","JPN":"欲しい本があったら言ってちょうだい。アタシが買ってあげる。","ENG":"If there are any books you want, let me know. I'll buy them for you.","TWN":"有想要的書就說吧，我買給你。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"괜찮아요. 요즘 매출이 저조해서 새로운 칵테일 연구나 해보려고요.","JPN":"大丈夫ですよ。最近売り上げがよくないから、新しいカクテルでも研究しようと思ってます。","ENG":"It's all right. Sales are low these days, so I was thinking of researching new cocktail recipes.","TWN":"不用了。最近營業額不太好，我想研究一下新的雞尾酒。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"귀찮아.","JPN":"面倒だ。","ENG":"What a bother.","TWN":"真麻煩。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};